import org.joda.time.Chronology;
import org.joda.time.DateTimeFieldType;
import org.joda.time.DurationField;
import org.joda.time.chrono.ISOChronology;

public class DebugPartial {
    public static void main(String[] args) {
        Chronology chrono = ISOChronology.getInstanceUTC();

        DateTimeFieldType hourType = DateTimeFieldType.hourOfDay();
        DateTimeFieldType clockHourType = DateTimeFieldType.clockhourOfDay();

        DurationField hourUnit = hourType.getDurationType().getField(chrono);
        DurationField clockHourUnit = clockHourType.getDurationType().getField(chrono);

        System.out.println("Hour Unit: " + hourUnit);
        System.out.println("ClockHour Unit: " + clockHourUnit);
        System.out.println("Unit Compare: " + hourUnit.compareTo(clockHourUnit));

        DurationField hourRange = hourType.getRangeDurationType().getField(chrono);
        DurationField clockHourRange = clockHourType.getRangeDurationType().getField(chrono);

        System.out.println("Hour Range: " + hourRange);
        System.out.println("ClockHour Range: " + clockHourRange);
        System.out.println("Range Compare: " + hourRange.compareTo(clockHourRange));
    }
}

