public static void main(String[] args) {
    Chronology chrono = ISOChronology.getInstanceUTC();

    DateTimeFieldType hourType = DateTimeFieldType.hourOfDay();
    DateTimeFieldType clockHourType = DateTimeFieldType.clockhourOfDay();

    try {
        System.out.println("Attempting to create Partial with hourOfDay and clockhourOfDay...");
        org.joda.time.Partial p = new org.joda.time.Partial(
            new DateTimeFieldType[] {hourType, clockHourType},
            new int[] {10, 10},
            chrono
        );
        System.out.println("Partial created successfully: " + p);
    } catch (IllegalArgumentException e) {
        System.out.println("Caught expected exception: " + e.getMessage());
    } catch (Exception e) {
        System.out.println("Caught unexpected exception: " + e);
        e.printStackTrace();
    }
}

